    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int currentSize, front, maxSize;
        cin >> currentSize >> front >> maxSize;
        bool empty = (currentSize == 0);
        bool full  = (currentSize == maxSize);
        cout << (empty ? "Queue is Empty" : "Queue is Not Empty") << '\n';
        cout << (full ? "Queue is Full" : "Queue is Not Full") << '\n';
        cout << "Current Size: " << currentSize << '\n';
    }
    return 0;
}

