            st = new StringTokenizer(br.readLine());
            int currentSize = Integer.parseInt(st.nextToken());
            int front = Integer.parseInt(st.nextToken()); // not used
            int maxSize = Integer.parseInt(st.nextToken());
            boolean empty = currentSize == 0;
            boolean full = currentSize == maxSize;
            sb.append(empty ? "Queue is Empty" : "Queue is Not Empty").append('\n');
            sb.append(full ? "Queue is Full" : "Queue is Not Full").append('\n');
            sb.append("Current Size: ").append(currentSize).append('\n');
        }
        System.out.print(sb.toString());
